#include<bits/stdc++.h>
using namespace std;
deque<int> d;
int n, k, a[2000005];
int main() {
	cin >> n >> k;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i < k; i++) {
		while (!d.empty() && a[i] > a[d.back()]) {
			d.pop_back();
		}
		d.push_back(i);
	}
	for (int i = k; i <= n; i++) {
		while (!d.empty() && a[i] > a[d.back()]) {
			d.pop_back();
		}
		while (!d.empty() && d.front() <= i - k) {
			d.pop_front();
		}
		d.push_back(i);
		cout<<a[d.front()]<<"\n";
	}
	return 0;
}
